    "/sp/global/targets/bid/recommendations": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        get?: never;
        put?: never;
        /**
         * Get bid recommendations for multi-country ad groups
         * @description The <b> POST /sp/targets/bid/recommendations </b> endpoint returns recommended bids for each target given either A) new ad group (a list of ad ASINs) or B) existing ad group (a campaign ID and ad group ID). Please use the recommendationType field to specify if you want to use option A or option B. This API is currently available at marketplaces where SP is available. The API supports keyword, auto and product targets. The API will return a 422 response when an unsupported marketplace or target is provided. <h1> Version 5.0 </h1><h2> New Features </h2><ul><li> Version 5.0 introduces two new capabilities. First, advertisers will receive the estimated impressions for the suggested bid to help them understand the potential impact of adopting them. Second, advertisers will get a view of the estimated impressions for a range of bids (8 bids) for each target. </li><li> The second feature is default to be disabled. To enable it, user needs to set <b> includeAnalysis </b> as True in request body. </li><li> New features are currently available only for existing ad group requests in US marketplace. </li></ul><h1> Version 4.0 </h1><h2> New Features </h2><ul><li> Version 4.0 allows users to get theme-based bid recommendations for product targeting expressions, including PAT_ASIN, PAT_CATEGORY and PAT_CATEGORY_REFINEMENT. </li><li> Version 4.0 supports keyword, auto and product targets in all marketplaces. </li><li> Version 4.0 removes "impact metrics" when returning each bid suggestion. </li><li> Version 4.0 also allows users to get theme-based bid recommendations for keyword group targeting expressions with the type KEYWORD_GROUP. This new type is only available in US marketplace. </li></ul><br>
         *
         *     **Authorized resource type**:
         *     Global Ad Account ID
         *
         *     **Parameter name**:
         *     Amazon-Ads-AccountId
         *
         *     **Parameter in**:
         *     header
         *
         *     **Requires one of these permissions**:
         *     ["advertiser_campaign_edit","advertiser_campaign_view"]
         */
        post: operations["GetMultiCountryThemeBasedBidRecommendationForAdGroup_v1"];
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
    "/sp/global/targets/keywords/recommendations/list": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        get?: never;
        put?: never;
        /**
         * Get global keyword recommendations
         * @description The <b> POST /sp/global/targets/keywords/recommendations/list </b> endpoint returns recommended keyword targets for a list of countries given either A) a list of ad ASINs per target country or B) a global campaign ID and ad group ID. Please use the recommendationType field to specify if you want to use option A or option B. This endpoint will also return recommended bids along with each recommendation keyword target.<br><br> <b> Asins</b> <br>Global API endpoint accepts <b>asins</b> array. Item is a <b>country asin map</b> Key is the 2-letter country code. Value is an asin.<br><br> <b> Targets</b> <br>Global API endpoint accepts <b>targets</b> array. Item is a <b>country target object</b> Object has two fields: matchType and countryKeywords. CountryKeywords is a map with a key as the 2-letter country code and value as a keyword object. <br/><br/>Each country will be processed in parallel according to rules of <a href="https://advertising.amazon.com/API/docs/en-us/sponsored-products/3-0/openapi/prod#tag/Keyword-Targets:~:text=keywords/localize%20endpoint.-,Version%205.0,-New%20Features">version 5</a> recommendation API.<h3> Availability </h3> Global keyword recommendation API is available in all the marketplaces.
         *
         *     **Authorized resource type**:
         *     Global Ad Account ID, Profile ID
         *
         *     **Parameter name**:
         *     Amazon-Ads-AccountId
         *
         *     **Parameter in**:
         *     header
         *
         *     **Requires one of these permissions**:
         *     ["advertiser_campaign_edit","advertiser_campaign_view"]
         */
        post: operations["getGlobalRankedKeywordRecommendation"];
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
